import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Box<T> ‚Äî Single Ownership Heap Pointer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/memory/box.md","filePath":"guide/memory/box.md"}'),o={name:"guide/memory/box.md"};function i(l,e,r,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="box-t-‚Äî-single-ownership-heap-pointer" tabindex="-1">Box&lt;T&gt; ‚Äî Single Ownership Heap Pointer <a class="header-anchor" href="#box-t-‚Äî-single-ownership-heap-pointer" aria-label="Permalink to &quot;Box\\&lt;T\\&gt; ‚Äî Single Ownership Heap Pointer&quot;">‚Äã</a></h1><p><code>Box&lt;T&gt;</code> is Vex&#39;s primary smart pointer for heap allocation. It provides <strong>single ownership</strong> of the data it points to and automatically cleans up memory when it goes out of scope.</p><div class="tip custom-block"><p class="custom-block-title">Prelude Type</p><p><code>Box&lt;T&gt;</code> is a <strong>prelude type</strong> ‚Äî available in all Vex programs without any <code>import</code>.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">‚Äã</a></h2><p>A <code>Box</code> allows you to store data on the heap rather than the stack. This is useful for:</p><ol><li><strong>Large data structures</strong>: Moving a <code>Box</code> only copies a pointer, not the entire data.</li><li><strong>Recursive types</strong>: Enums or structs that contain themselves.</li><li><strong>Ownership transfer</strong>: Passing data between functions without deep copying.</li></ol><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    // Allocate an integer on the heap</span></span>
<span class="line"><span>    let b = Box.new(42);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Automatic cleanup happens when &#39;b&#39; goes out of scope</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="vumm-integration" tabindex="-1">VUMM Integration <a class="header-anchor" href="#vumm-integration" aria-label="Permalink to &quot;VUMM Integration&quot;">‚Äã</a></h2><p><code>Box&lt;T&gt;</code> is fully integrated with <strong>VUMM (Unified Memory Management)</strong>. It follows the RAII (Resource Acquisition Is Initialization) pattern:</p><ul><li><strong>Allocation</strong>: Happens via <code>Box.new(value)</code>.</li><li><strong>Cleanup</strong>: The <code>drop()</code> method is called automatically by the compiler when the <code>Box</code> is no longer reachable. If <code>T</code> implements <code>$Drop</code>, its destructor is also called.</li></ul><h2 id="recursive-types" tabindex="-1">Recursive Types <a class="header-anchor" href="#recursive-types" aria-label="Permalink to &quot;Recursive Types&quot;">‚Äã</a></h2><p>Recursive types must be &quot;boxed&quot; because their size cannot be determined at compile time otherwise.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum List&lt;T&gt; {</span></span>
<span class="line"><span>    Cons(T, Box&lt;List&lt;T&gt;&gt;),</span></span>
<span class="line"><span>    Nil</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let list = List.Cons(1, Box.new(List.Cons(2, Box.new(List.Nil))));</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">‚Äã</a></h2><h3 id="constructors" tabindex="-1">Constructors <a class="header-anchor" href="#constructors" aria-label="Permalink to &quot;Constructors&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>Box.new(value: T)</code></td><td>Allocates heap memory and moves <code>value</code> into it.</td></tr></tbody></table><h3 id="instance-methods" tabindex="-1">Instance Methods <a class="header-anchor" href="#instance-methods" aria-label="Permalink to &quot;Instance Methods&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>drop()</code></td><td>Manually triggers cleanup (rarely needed, usually automatic).</td></tr></tbody></table><h2 id="memory-layout" tabindex="-1">Memory Layout <a class="header-anchor" href="#memory-layout" aria-label="Permalink to &quot;Memory Layout&quot;">‚Äã</a></h2><p>A <code>Box&lt;T&gt;</code> is represented as a single machine-word pointer to the heap allocation.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stack          Heap</span></span>
<span class="line"><span>+-------+      +-------+</span></span>
<span class="line"><span>| Box b | ---&gt; | Value | (T)</span></span>
<span class="line"><span>+-------+      +-------+</span></span></code></pre></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">‚Äã</a></h2><ul><li><a href="./vumm">VUMM</a> ‚Äî Vex&#39;s memory architecture</li><li><a href="./ownership">Ownership</a> ‚Äî Ownership and borrowing</li><li><a href="./ptr-t">Ptr&lt;T&gt;</a> ‚Äî Low-level typed pointers</li></ul>`,23)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
